curl -sS -X POST 'http://127.0.0.1:8021/api/attribute' -H 'Content-Type: application/json' --data-raw '{"judge": {"actual": {"actual_answer": "轻症赔付次数和金额取决于具体保险合同。一般情况下，轻症可以赔付多次，每次赔付金额通常为基本保险金额的20%至30%，且可能有次数上限（如3次或5次）和间隔期要求。建议查阅您的保险合同条款获取准确信息。"}, "boundary_decision": {"within_evaluable_scope": true}, "business_expectations": [{"downstream_consumer": "", "expectation_id": "明确说明轻症可多次赔付", "expected_outcome": "", "priority": "normal", "user_intent": ""}, {"downstream_consumer": "", "expectation_id": "提供轻症每次赔付金额比例范围", "expected_outcome": "", "priority": "normal", "user_intent": ""}, {"downstream_consumer": "", "expectation_id": "提及轻症赔付次数上限或常见次数", "expected_outcome": "", "priority": "normal", "user_intent": ""}, {"downstream_consumer": "", "expectation_id": "提及轻症赔付间隔期要求", "expected_outcome": "", "priority": "normal", "user_intent": ""}, {"downstream_consumer": "", "expectation_id": "提供影响多次赔付的关键限制条件如分组限制或累计赔付上限", "expected_outcome": "", "priority": "normal", "user_intent": ""}, {"downstream_consumer": "", "expectation_id": "提醒以合同条款为准并建议查阅或咨询", "expected_outcome": "", "priority": "normal", "user_intent": ""}, {"downstream_consumer": "", "expectation_id": "回答与参考回答及通用保险知识一致无矛盾", "expected_outcome": "", "priority": "normal", "user_intent": ""}], "consumer_contract": {"expected_clarity": "回答应清晰无歧义", "expected_completeness": "应覆盖次数、金额、关键限制条件等核心维度", "expected_correctness": "事实性信息的准确性应与通用保险条款一致", "expected_risk_control": "应提醒以合同为准，避免法律/合规风险"}, "evaluation_boundary": {"evidence_used": ["reference.actual_answer", "actual_answer", "通用保险知识"], "scenario": "qa_gold_answer"}, "evidence": [{"content": "轻症赔付次数和金额取决于具体保险合同。一般情况下，轻症可以赔付多次，每次赔付金额通常为基本保险金额的20%至30%，且可能有次数上限（如3次或5次）和间隔期要求。建议查阅您的保险合同条款获取准确信息。", "source": "actual_answer"}, {"content": "通常情况下，您购买的重疾险合同中关于轻症责任的赔付规则如下：1. 轻症可以多次赔付，具体次数以合同约定为准（常见为3-5次）。每次确诊的轻症需满足合同定义的疾病标准，且两次轻症确诊之间通常有间隔期（如90天或180天）。2. 每次轻症赔付的金额一般为基本保额的一定比例，常见比例为20%-30%。例如保额50万，每次轻症可赔付10万-15万。部分产品轻症赔付后重疾保额不变，部分产品会相应减少。3. 需要注意，轻症责任可能设有分组限制，即同一组别的轻症只能赔付一次；另外，轻症赔付后合同继续有效，但累计赔付上限可能有限制。以上为一般规则，具体赔付条件、次数、金额比例请以您持有的保险合同条款为准。建议您查阅合同中的“保险责任”及“轻症疾病保险金”章节，或直接咨询保险公司客服获取准确信息。", "source": "reference.actual_answer"}, "scenario=qa_gold_answer", "question_present=True", "actual_answer_present=True", "reference_answer_present=True"], "expected": {"actual_answer": "通常情况下，您购买的重疾险合同中关于轻症责任的赔付规则如下：\n1. 轻症可以多次赔付，具体次数以合同约定为准（常见为3-5次）。每次确诊的轻症需满足合同定义的疾病标准，且两次轻症确诊之间通常有间隔期（如90天或180天）。\n2. 每次轻症赔付的金额一般为基本保额的一定比例，常见比例为20%-30%。例如保额50万，每次轻症可赔付10万-15万。部分产品轻症赔付后重疾保额不变，部分产品会相应减少。\n3. 需要注意，轻症责任可能设有分组限制，即同一组别的轻症只能赔付一次；另外，轻症赔付后合同继续有效，但累计赔付上限可能有限制。\n以上为一般规则，具体赔付条件、次数、金额比例请以您持有的保险合同条款为准。建议您查阅合同中的“保险责任”及“轻症疾病保险金”章节，或直接咨询保险公司客服获取准确信息。"}, "fulfillment_assessments": [{"blocking": false, "downstream_impact": "", "expectation_id": "明确说明轻症可多次赔付", "status": "fulfilled"}, {"blocking": false, "downstream_impact": "", "expectation_id": "提供轻症每次赔付金额比例范围", "status": "fulfilled"}, {"blocking": false, "downstream_impact": "", "expectation_id": "提及轻症赔付次数上限或常见次数", "status": "fulfilled"}, {"blocking": false, "downstream_impact": "", "expectation_id": "提及轻症赔付间隔期要求", "status": "fulfilled"}, {"blocking": false, "downstream_impact": "", "expectation_id": "提供影响多次赔付的关键限制条件如分组限制或累计赔付上限", "status": "not_fulfilled"}, {"blocking": false, "downstream_impact": "", "expectation_id": "提醒以合同条款为准并建议查阅或咨询", "status": "fulfilled"}, {"blocking": false, "downstream_impact": "", "expectation_id": "回答与参考回答及通用保险知识一致无矛盾", "status": "fulfilled"}], "intent_model": {"constraints": ["答案应基于通用保险知识或合同条款", "需要明确是否可多次赔付", "需要量化赔付金额比例", "应考虑实际赔付中的限制条件"], "context": "用户已购买重疾险，问题来源于对合同条款的理解需求", "primary_intent": "了解重疾险中轻症责任的赔付次数及每次赔付金额规则"}, "judge_basis": "基于提供的黄金参考答案（reference.actual_answer）和通用重疾险知识，对比实际答案的准确性、完整性和有用性。", "judge_method": "将实际答案与黄金参考答案进行逐项对比，检查关键信息点（次数、比例、间隔期、限制条件、免责提示）的覆盖情况和信息一致性，同时评估回答是否可能引起误解。", "missing": [{"error_type": "", "evidence_ref": "", "incomplete": false, "kind": "missing", "raw": {"expectation_id": "提供影响多次赔付的关键限制条件如分组限制或累计赔付上限", "item": "轻症分组限制的说明", "reason": "用户可能不知道同一组别的轻症只能赔付一次，缺失可能导致误解", "r